import React,{useEffect,useCallback}from 'react'
import {ReactNavbar} from "react-responsive-animate-navbar";

const Navbar = () => {
    const onScrollClick = () => {

        const children = document.querySelectorAll(".styles_navLinks__38tON ul li");
        children.forEach(function (child) {
            // var a = document.getElementById(child);
            child.setAttribute("href", "#aboutme");
            child.addEventListener('click', (e) => {

                    window.scrollTo({
                        top: 400,
                        behavior: 'smooth',
                    })
                }
            );
            // child.addEventListener('click', function(event){
            //     event.preventDefault();
            //     window.scrollTo(document.querySelector('#aboutme').offsetTop);
            //     // $('html, body').animate({
            //     //     scrollTop: $( $.attr(this, 'href') ).offset().top
            //     // }, 500);
            // });
            // child.href = "#aboutme";
            console.log(child);
            child.click();
        });
    }

    return (
        <div onClick = {() => onScrollClick}>
        <ReactNavbar
            color="rgb(25,100,50)"
            logo='logo-removebg-preview.png'

            menu={[
                { name: "HOME", to: "/" },
                { name: "ABOUT ME", to: "aboutme" },
                { name: "PROJECT", to: "project" },
                { name: "CONTACT", to: "contact" },
            ]}
            social={[
                {
                    name: "Linkedin",
                    url: "https://www.linkedin.com/in/daniel-lee-00991085",
                    icon: ["fab", "linkedin-in"],
                },
                {
                    name: "Github",
                    url: "https://github.com/DMZnoo",
                    icon: ["fab", "github"],
                }
            ]}

        />
        </div>
    )
};
export default Navbar;
